using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;
Ptr ui;

bool CreateCylinder(Ptr occ, double diameter, double height, bool isSolid)
{
    Ptr comp = occ->component();
    if (!comp)
        return false;
    Ptr sketches = comp->sketches();
    if (!sketches)
        return false;
    Ptr xzPlane = comp->xZConstructionPlane();
    if (!xzPlane)
        return false;
    Ptr sketch = sketches->add(xzPlane);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr sketchCircle = sketchCircles->addByCenterRadius(centerPoint, diameter);
    if (!sketchCircle)
        return false;

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr profile = profs->item(0);
    if (!profile)
        return false;

    // Create an extrude input
    Ptr feats = comp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(profile, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Set the extrude input
    Ptr distance = ValueInput::createByReal(height);
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);
    extInput->isSolid(isSolid);

    // Create the extrude
    Ptr extrude = extrudes->add(extInput);
    if (!extrude)
        return false;

    return true;
}

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create four sub components under root component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;

    // sub component 1
    Ptr transform0 = adsk::core::Matrix3D::create();
    if (!transform0)
        return false;
    Ptr vector3d0 = adsk::core::Vector3D::create(10.0, 0.0, 0.0);
    if (!vector3d0)
        return false;
    transform0->translation(vector3d0);
    Ptr subOcc0 = occs->addNewComponent(transform0);
    if (!subOcc0)
        return false;

    // sub component 2
    Ptr transform1 = adsk::core::Matrix3D::create();
    if (!transform1)
        return false;
    Ptr vector3d1 = adsk::core::Vector3D::create(0.0, 0.0, 12.0);
    if (!vector3d1)
        return false;
    transform1->translation(vector3d1);
    Ptr subOcc1 = occs->addNewComponent(transform1);
    if (!subOcc1)
        return false;

    // sub component 3
    Ptr transform2 = adsk::core::Matrix3D::create();
    if (!transform2)
        return false;
    Ptr vector3d2 = adsk::core::Vector3D::create(-8.0, 0.0, 0.0);
    if (!vector3d2)
        return false;
    transform2->translation(vector3d2);
    Ptr subOcc2 = occs->addNewComponent(transform2);
    if (!subOcc2)
        return false;

    // sub component 4
    Ptr transform3 = adsk::core::Matrix3D::create();
    if (!transform3)
        return false;
    Ptr vector3d3 = adsk::core::Vector3D::create(0.0, 0.0, -6.0);
    if (!vector3d3)
        return false;
    transform3->translation(vector3d3);
    Ptr subOcc3 = occs->addNewComponent(transform3);
    if (!subOcc3)
        return false;

    // Create an object collection of occurrences
    Ptr occGroups = adsk::core::ObjectCollection::create();
    if (!occGroups)
        return false;
    occGroups->add(subOcc0);
    occGroups->add(subOcc1);
    occGroups->add(subOcc2);
    occGroups->add(subOcc3);

    // Create four cylinders in four sub components
    bool result0 = CreateCylinder(subOcc0, 0.5, 5, false);
    if (!result0)
        return false;

    bool result1 = CreateCylinder(subOcc1, 0.75, 7.5, false);
    if (!result1)
        return false;

    bool result2 = CreateCylinder(subOcc2, 1.0, 10, false);
    if (!result2)
        return false;

    bool result3 = CreateCylinder(subOcc3, 1.25, 12.5, false);
    if (!result3)
        return false;

    // Create a RigidGroup
    bool isIncludeChildren = true;
    Ptr rigidGroups_ = rootComp->rigidGroups();
    if (!rigidGroups_)
        return false;
    Ptr rigidGroup = rigidGroups_->add(occGroups, isIncludeChildren);
    if (!rigidGroup)
        return false;

    // Fit to window
    Ptr viewPort = app->activeViewport();
    if (!viewPort)
        return false;
    Ptr cam = viewPort->camera();
    if (!cam)
        return false;
    cam->isFitView(true);
    viewPort->camera(cam);


    return true;
}
